import{_ as a,o as i,c as o,ag as r}from"./chunks/framework.ByAj6Cie.js";const m=JSON.parse('{"title":"Fundamentos de arco eléctrico","description":"","frontmatter":{},"headers":[],"relativePath":"es/power-systems/protection/arc-flash-basics.md","filePath":"es/power-systems/protection/arc-flash-basics.md"}'),n={name:"es/power-systems/protection/arc-flash-basics.md"};function l(c,e,s,t,d,p){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="fundamentos-de-arco-electrico" tabindex="-1">Fundamentos de arco eléctrico <a class="header-anchor" href="#fundamentos-de-arco-electrico" aria-label="Permalink to &quot;Fundamentos de arco eléctrico&quot;">​</a></h1><h2 id="descripcion-general" tabindex="-1">Descripción general <a class="header-anchor" href="#descripcion-general" aria-label="Permalink to &quot;Descripción general&quot;">​</a></h2><p>El arco eléctrico es un evento eléctrico peligroso en el que un arco no intencional libera una gran cantidad de energía en un tiempo muy corto.</p><p>Produce calor extremo, luz intensa, ondas de presión y metal fundido, creando riesgos serios para el personal y el equipo.</p><p>El arco eléctrico puede ocurrir tanto en sistemas de baja como de media tensión, especialmente durante fallas u operación inadecuada.</p><h2 id="proposito" tabindex="-1">Propósito <a class="header-anchor" href="#proposito" aria-label="Permalink to &quot;Propósito&quot;">​</a></h2><p>Comprender el arco eléctrico es esencial para:</p><ul><li>Proteger al personal que trabaja en o cerca de equipo energizado</li><li>Reducir el riesgo de lesiones graves y fatalidades</li><li>Limitar el daño al equipo eléctrico</li><li>Definir prácticas de trabajo seguras y medidas de protección</li></ul><p>El diseño y los procedimientos adecuados ayudan a reducir tanto la probabilidad como el impacto de los eventos de arco eléctrico.</p><h2 id="como-funciona" tabindex="-1">Cómo funciona <a class="header-anchor" href="#como-funciona" aria-label="Permalink to &quot;Cómo funciona&quot;">​</a></h2><p>Un arco eléctrico ocurre cuando la corriente eléctrica fluye a través del aire entre conductores o entre un conductor y tierra.</p><p>Esto puede ser causado por:</p><ul><li>Falla de aislamiento</li><li>Conexiones flojas</li><li>Polvo, humedad o contaminación</li><li>Contacto accidental con herramientas u objetos conductores</li></ul><p>Una vez iniciado, el arco crea un plasma que permite que fluya corriente muy alta.</p><p>Esto resulta en:</p><ul><li>Elevación rápida de temperatura, a menudo superior a varios miles de grados</li><li>Expansión del aire, creando una onda de presión</li><li>Emisión de luz y sonido intensos</li></ul><p>La severidad de un arco eléctrico depende de:</p><ul><li>La corriente de falla disponible</li><li>La duración del arco</li><li>La distancia desde la fuente</li></ul><h2 id="aplicaciones" tabindex="-1">Aplicaciones <a class="header-anchor" href="#aplicaciones" aria-label="Permalink to &quot;Aplicaciones&quot;">​</a></h2><p>Las consideraciones de arco eléctrico aplican a:</p><ul><li>Switchgear (celdas de media tensión) y equipo de media tensión</li><li>Tableros de distribución y paneles de distribución</li><li>Centros de control de motores</li><li>Cuartos eléctricos y subestaciones</li><li>Cualquier ubicación donde se pueda acceder a equipo energizado</li></ul><p>Es relevante donde se realiza mantenimiento, operación o diagnóstico.</p><h2 id="consideraciones-clave" tabindex="-1">Consideraciones clave <a class="header-anchor" href="#consideraciones-clave" aria-label="Permalink to &quot;Consideraciones clave&quot;">​</a></h2><ul><li><p><strong>Energía incidente</strong><br> Determina la severidad del arco y las medidas de protección requeridas</p></li><li><p><strong>Tiempo de despeje</strong><br> Una protección más rápida reduce significativamente la energía del arco</p></li><li><p><strong>Distancia de trabajo</strong><br> La distancia desde la fuente del arco afecta el nivel de exposición</p></li><li><p><strong>Diseño del equipo</strong><br> El equipo resistente al arco puede ayudar a contener la energía</p></li><li><p><strong>Coordinación de protección</strong><br> Las configuraciones adecuadas pueden reducir la duración de la falla y la severidad del arco</p></li><li><p><strong>Condición de mantenimiento</strong><br> Un mantenimiento deficiente aumenta la probabilidad de fallas por arco</p></li></ul><h2 id="notas-practicas" tabindex="-1">Notas prácticas <a class="header-anchor" href="#notas-practicas" aria-label="Permalink to &quot;Notas prácticas&quot;">​</a></h2><ul><li>Desenergizar el equipo es la forma más efectiva de eliminar el riesgo de arco eléctrico</li><li>El equipo de protección personal debe coincidir con los niveles de energía incidente calculados</li><li>Las conexiones flojas y la contaminación son desencadenantes comunes del arco eléctrico</li><li>Los dispositivos de protección más rápidos pueden reducir significativamente el riesgo de daño y lesiones</li><li>El etiquetado claro y el análisis de riesgos mejoran la seguridad durante la operación</li></ul>',26)])])}const f=a(n,[["render",l]]);export{m as __pageData,f as default};
